from flask import Flask, request, jsonify
from kafka import KafkaProducer
import re
import os

app = Flask(__name__)

# Initialize Kafka producer
producer = KafkaProducer(bootstrap_servers='localhost:9092')

# Define a list of allowed topics
ALLOWED_TOPICS = ['topic1', 'topic2', 'topic3']

# Function to validate topic names
def is_valid_topic_name(topic_name):
    return topic_name in ALLOWED_TOPICS

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    message = request.json.get('message')

    # Validate topic name
    if not is_valid_topic_name(topic_name):
        return jsonify({'error': 'Invalid topic name'}), 400

    # Validate message content
    if not isinstance(message, str) or not message:
        return jsonify({'error': 'Invalid message content'}), 400

    # Publish message to Kafka
    try:
        producer.send(topic_name, message.encode('utf-8'))
        producer.flush()
        return jsonify({'status': 'Message published successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=int(os.environ.get('PORT', 5000)))